const bookingData = items[0].json;

const providers = [
  {
    id: 'provider_1',
    priority: 1,
    name: process.env.PROVIDER_1_NAME,
    lineId: process.env.PROVIDER_1_LINE_ID,
    email: process.env.PROVIDER_1_EMAIL,
    active: true
  },
  {
    id: 'provider_2',
    priority: 2,
    name: process.env.PROVIDER_2_NAME,
    lineId: process.env.PROVIDER_2_LINE_ID,
    email: process.env.PROVIDER_2_EMAIL,
    active: true
  },
  {
    id: 'provider_3',
    priority: 3,
    name: process.env.PROVIDER_3_NAME,
    lineId: process.env.PROVIDER_3_LINE_ID,
    email: process.env.PROVIDER_3_EMAIL,
    active: true
  }
];

const activeProviders = providers.filter(p => p.active).sort((a, b) => a.priority - b.priority);

return [{
  json: {
    ...bookingData,
    providers: activeProviders,
    currentProviderIndex: 0,
    currentProvider: activeProviders[0],
    // Generate location selection URL for provider
    locationSelectionUrl: `${process.env.N8N_HOST}/webhook/select-location?booking=${bookingData.bookingId}`
  }
}];

