// Generate HTML for location selection interface
const params = items[0].json.query;
const bookingId = params.booking;
const action = params.action; // 'confirm' or 'alternative'

// Fetch booking data from Google Sheets
const booking = $node['Fetch Booking Data'].json;

const html = `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${action === 'confirm' ? 'Confirm Booking' : 'Select Alternative Location'}</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f5f5f5; }
        .container { max-width: 600px; margin: 0 auto; background: white; min-height: 100vh; }
        .header { background: ${action === 'confirm' ? 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)' : 'linear-gradient(135deg, #ff9966 0%, #ff5e62 100%)'}; color: white; padding: 20px; text-align: center; }
        .header h1 { font-size: 24px; margin-bottom: 5px; }
        .header p { font-size: 14px; opacity: 0.9; }
        .content { padding: 20px; }
        .booking-info { background: #f8f9fa; padding: 15px; border-radius: 8px; margin-bottom: 20px; }
        .booking-info div { margin: 8px 0; }
        .booking-info strong { display: inline-block; width: 120px; }
        .form-group { margin-bottom: 20px; }
        .form-group label { display: block; font-weight: bold; margin-bottom: 8px; color: #333; }
        .form-group input, .form-group textarea { width: 100%; padding: 12px; border: 1px solid #ddd; border-radius: 5px; font-size: 16px; }
        .form-group textarea { resize: vertical; min-height: 80px; }
        #map { width: 100%; height: 400px; border: 2px solid #ddd; border-radius: 8px; margin-bottom: 15px; }
        .location-display { background: #e8f5e9; padding: 12px; border-radius: 5px; margin-bottom: 15px; display: none; }
        .location-display.show { display: block; }
        .btn { width: 100%; padding: 15px; border: none; border-radius: 5px; font-size: 18px; font-weight: bold; cursor: pointer; color: white; }
        .btn-confirm { background: #4caf50; }
        .btn-submit { background: #2196F3; }
        .btn:active { opacity: 0.8; }
        .instructions { background: #e3f2fd; padding: 12px; border-radius: 5px; margin-bottom: 20px; font-size: 14px; }
        .time-input { display: flex; gap: 10px; }
        .time-input input { flex: 1; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>${action === 'confirm' ? '✅ Confirm Booking' : '⚠️ Select Alternative Location'}</h1>
            <p>Booking: ${bookingId}</p>
        </div>

        <div class="content">
            <div class="booking-info">
                <div><strong>Tour:</strong> ${booking.tourName}</div>
                <div><strong>Date:</strong> ${booking.tourDate}</div>
                <div><strong>Customer:</strong> ${booking.customerName}</div>
                <div><strong>Guests:</strong> ${booking.numberOfPeople} people</div>
                <div><strong>Amount:</strong> ${booking.currency} ${booking.totalAmount}</div>
            </div>

            ${action === 'alternative' ? `
            <div class="instructions">
                📍 <strong>Current Location:</strong> ${booking.pickupLocation}<br>
                Please select a better pickup location with easier access.
            </div>
            ` : ''}

            <form id="locationForm">
                <input type="hidden" name="bookingId" value="${bookingId}">
                <input type="hidden" name="action" value="${action}">

                ${action === 'confirm' ? `
                <div class="form-group">
                    <label>⏰ Pickup Time *</label>
                    <input type="time" 
                           name="pickupTime" 
                           id="pickupTime" 
                           required 
                           placeholder="Select pickup time">
                    <small style="color: #666; margin-top: 5px; display: block;">Select any time that works for you</small>
                </div>
                ` : ''}

                ${action === 'alternative' ? `
                <div class="form-group">
                    <label>📍 Search for Location</label>
                    <input type="text" 
                           id="locationSearch" 
                           placeholder="Search for hotel, landmark, or address...">
                </div>

                <div class="form-group">
                    <label>🗺️ Select Location on Map (or search above)</label>
                    <div id="map"></div>
                    <div id="locationDisplay" class="location-display">
                        <strong>Selected:</strong> <span id="selectedLocation"></span>
                    </div>
                </div>

                <div class="form-group">
                    <label>📝 Location Name *</label>
                    <input type="text" 
                           name="locationName" 
                           id="locationName" 
                           required 
                           placeholder="e.g., Starbucks Sukhumvit Soi 11">
                </div>

                <input type="hidden" name="latitude" id="latitude">
                <input type="hidden" name="longitude" id="longitude">
                <input type="hidden" name="mapUrl" id="mapUrl">
                ` : ''}

                <button type="submit" class="btn ${action === 'confirm' ? 'btn-confirm' : 'btn-submit'}">
                    ${action === 'confirm' ? '✅ CONFIRM BOOKING' : '✅ UPDATE LOCATION'}
                </button>
            </form>
        </div>
    </div>

    <script src="https://maps.googleapis.com/maps/api/js?key=${process.env.GOOGLE_MAPS_API_KEY}&libraries=places"></script>
    <script>
        let map, marker, autocomplete;

        ${action === 'alternative' ? `
        // Initialize map for alternative location
        function initMap() {
            const defaultCenter = { 
                lat: ${booking.pickupLatitude || '13.7563'}, 
                lng: ${booking.pickupLongitude || '100.5018'} 
            };

            map = new google.maps.Map(document.getElementById('map'), {
                center: defaultCenter,
                zoom: 15
            });

            marker = new google.maps.Marker({
                map: map,
                position: defaultCenter,
                draggable: true,
                animation: google.maps.Animation.DROP
            });

            // Autocomplete
            autocomplete = new google.maps.places.Autocomplete(
                document.getElementById('locationSearch'),
                { types: ['establishment', 'geocode'] }
            );

            autocomplete.addListener('place_changed', function() {
                const place = autocomplete.getPlace();
                if (place.geometry) {
                    map.setCenter(place.geometry.location);
                    map.setZoom(17);
                    marker.setPosition(place.geometry.location);
                    updateLocationFields(place.geometry.location, place.formatted_address || place.name);
                }
            });

            // Click on map
            map.addListener('click', function(e) {
                marker.setPosition(e.latLng);
                reverseGeocode(e.latLng);
            });

            // Drag marker
            marker.addListener('dragend', function(e) {
                reverseGeocode(e.latLng);
            });
        }

        function reverseGeocode(latLng) {
            const geocoder = new google.maps.Geocoder();
            geocoder.geocode({ location: latLng }, function(results, status) {
                if (status === 'OK' && results[0]) {
                    updateLocationFields(latLng, results[0].formatted_address);
                }
            });
        }

        function updateLocationFields(latLng, address) {
            document.getElementById('latitude').value = latLng.lat();
            document.getElementById('longitude').value = latLng.lng();
            document.getElementById('mapUrl').value = \`https://www.google.com/maps?q=\${latLng.lat()},\${latLng.lng()}\`;
            document.getElementById('selectedLocation').textContent = address;
            document.getElementById('locationDisplay').classList.add('show');
            if (!document.getElementById('locationName').value) {
                document.getElementById('locationName').value = address;
            }
        }

        window.onload = initMap;
        ` : ''}

        // Form submission
        document.getElementById('locationForm').addEventListener('submit', function(e) {
            e.preventDefault();

            const formData = new FormData(this);
            const data = Object.fromEntries(formData.entries());

            // Submit to N8N webhook
            fetch('/webhook/provider-response', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            })
            .then(response => response.json())
            .then(data => {
                alert('✅ Booking updated successfully! Closing...');
                window.close();
            })
            .catch(error => {
                alert('Error: ' + error.message);
            });
        });
    </script>
</body>
</html>
`;

return [{ json: { htmlContent: html } }];

// Parse provider response
const response = items[0].json;
const action = response.action;

let result = {
  bookingId: response.bookingId,
  timestamp: new Date().toISOString()
};

if (action === 'confirm') {
  result.status = 'confirmed';
  result.pickupTime = response.pickupTime;
  result.action = 'confirm';
} else if (action === 'alternative') {
  result.status = 'alternative_location_set';
  result.alternativeLocation = response.locationName;
  result.alternativeLocationLat = response.latitude;
  result.alternativeLocationLng = response.longitude;
  result.alternativeLocationMapUrl = response.mapUrl;
  result.action = 'alternative';
}

return [{ json: result }];
